        // Add the $attributes array as the 4th parameter
        public static function get(string $iconName, int $size = 20, array $attributes = [])
        {
            $path = self::PATHS[strtolower($iconName)] ?? null;

            if ($path === null)
            {
                return '';
            }

            // 1. Define the mandatory SVG properties
            $coreAttributes = [
                'xmlns' => 'http://www.w3.org/2000/svg',
                'viewBox' => "0 0 640 640",
                'width' => (string)$size,
                'height' => (string)$size,
                'fill' => 'currentColor'
            ];

            // 2. Intelligently merge the base class with any custom classes you pass in
            $baseClass = 'wasd-icon';
            $attributes['class'] = isset($attributes['class']) ? "{$baseClass} {$attributes['class']}" : $baseClass;

            // 3. Combine the core properties with your custom attributes
            $finalAttributes = [...$coreAttributes, ...$attributes];

            // 4. Transform the array into a valid HTML string (e.g., class="wasd-icon my-class" style="color: red;")
            $attrString = '';
            foreach ($finalAttributes as $key => $value) {
                $attrString .= htmlspecialchars($key) . '="' . htmlspecialchars((string)$value) . '" ';
            }

            // 5. Inject the compiled string directly into the SVG tag
            return "<svg " . trim($attrString) . "><path d=\"{$path}\"/></svg>";
        }
    }
